class X{_renderMiniTestCard(){const el=document.getElementById("an-mini-test-card");if(!el)return;const today=new Date().toISOString().slice(0,10);const lastDate=this.state.get("miniTestLastDate")||"";const lastResult=this.state.get("miniTestLastResult")||null;const weekAgo=new Date(Date.now()-7*24*60*60*1e3).toISOString().slice(0,10);const available=!lastDate||lastDate<weekAgo;if(available){el.innerHTML='<div class="mt-ready"><div class="mt-ready-icon">🧪</div><div class="mt-ready-txt">Bu haftanın mini testi hazır!</div><div class="mt-ready-sub">5 soruluk hızlı CEFR kontrolü</div><button class="btn mt-start-btn" onclick="window._app._startMiniTest()">Testi Başlat →</button></div>';}else{const pct=Math.round((lastResult?.score||0)/5*100);const col=pct>=80?"#10b981":pct>=60?"#00d4ff":"#f43f5e";el.innerHTML='<div class="mt-done"><div class="mt-done-top"><span class="mt-done-icon">✅</span><div><div class="mt-done-title">Bu haftaki test tamamlandı</div><div class="mt-done-date">'+lastDate+'</div></div></div><div class="mt-done-score" style="color:'+col+'">'+((lastResult?.score)||0)+'/5 Doğru &mdash; '+(lastResult?.level||"")+' Seviyesi</div><button class="btn mt-retry-btn" style="margin-top:10px;opacity:0.55;font-size:0.78rem" onclick="window._app._startMiniTest()">Tekrar Dene</button></div>';}}_startMiniTest(){const el=document.getElementById("an-mini-test-card");if(!el)return;const pool=[{level:"A1",q:"I ___ a student.",choices:["am","is","are","be"],ans:0},{level:"A1",q:"There ___ two books.",choices:["is","are","am","has"],ans:1},{level:"A2",q:"She ___ coffee every morning.",choices:["drink","drinks","drank","is drink"],ans:1},{level:"A2",q:"They ___ TV when I arrived.",choices:["watched","watching","were watching","watch"],ans:2},{level:"B1",q:"I wish I ___ more time.",choices:["have","had","has","will have"],ans:1},{level:"B1",q:"The report ___ by Tom.",choices:["wrote","was written","is writing","has written"],ans:1},{level:"B2",q:"___ you finish early, call me.",choices:["Would","Should","If","Despite"],ans:2},{level:"B2",q:"He insisted that she ___ the truth.",choices:["told","tell","tells","had told"],ans:1},{level:"C1",q:"The deal fell ___ at the last minute.",choices:["out","through","down","off"],ans:1},{level:"C1",q:"___ circumstances, I would have helped.",choices:["Under other","In other","With other","By other"],ans:0}];const pick=[];const levels=["A1","A2","B1","B2","C1"];for(const lv of levels){const group=pool.filter(q=>q.level===lv);pick.push(group[Math.floor(Math.random()*group.length)]);}this.session.miniTest={questions:pick,idx:0,score:0};this._renderMiniTestQuestion()}_renderMiniTestQuestion(){const el=document.getElementById("an-mini-test-card");if(!el)return;const mt=this.session.miniTest;if(!mt)return;const q=mt.questions[mt.idx];const num=mt.idx+1;const total=mt.questions.length;el.innerHTML='<div class="mt-quiz"><div class="mt-quiz-hd"><span class="mt-q-num">'+num+'/'+total+'</span><span class="mt-q-level">'+q.level+'</span></div><div class="mt-q-text">'+q.q+'</div><div class="mt-choices">'+q.choices.map((c,i)=>'<button class="mt-choice" onclick="window._app._answerMiniTest('+i+')">'+c+'</button>').join("")+'</div></div>'}_answerMiniTest(idx){const mt=this.session.miniTest;if(!mt)return;if(idx===mt.questions[mt.idx].ans)mt.score++;mt.idx++;if(mt.idx<mt.questions.length){this._renderMiniTestQuestion();}else{this._finishMiniTest();}}_finishMiniTest(){const mt=this.session.miniTest;if(!mt)return;const score=mt.score;const total=mt.questions.length;const today=new Date().toISOString().slice(0,10);const CEFR_ORDER=["A1","A2","B1","B2","C1","C2"];const currentLevel=this.state.get("cefrLevel")||"A1";const pct=Math.round(score/total*100);let suggestLevel=currentLevel;if(pct>=80){const ci=CEFR_ORDER.indexOf(currentLevel);if(ci<CEFR_ORDER.length-1)suggestLevel=CEFR_ORDER[ci+1];}else if(pct<=40){const ci=CEFR_ORDER.indexOf(currentLevel);if(ci>0)suggestLevel=CEFR_ORDER[ci-1];}this.state.set("miniTestLastDate",today);this.state.set("miniTestLastResult",{score,level:currentLevel,date:today});const el=document.getElementById("an-mini-test-card");if(!el)return;const col=pct>=80?"#10b981":pct>=60?"#00d4ff":"#f43f5e";const msg=pct>=80?"🎉 Mükemmel!":pct>=60?"💪 İyi!":"📚 Daha fazla pratik!";let suggestHtml="";if(suggestLevel!==currentLevel){suggestHtml='<button class="btn cf-lu-btn" style="margin-top:12px" onclick="window._app.upgradeCefrLevel(this.dataset.lv)" data-lv="'+suggestLevel+'">'+suggestLevel+' Seviyesine Geç →</button>';}el.innerHTML='<div class="mt-result"><div class="mt-result-score" style="color:'+col+'">'+score+'/'+total+'</div><div class="mt-result-msg">'+msg+'</div><div class="mt-result-pct" style="color:'+col+'">%'+pct+'</div>'+suggestHtml+'</div>';}}